async function resolveCategoryId(categoryName) {
  const cat = await prisma.scaleCategory.findFirst({
    where: { name: categoryName },
  });
  if (cat) return cat.id;
  const fallback = await prisma.scaleCategory.findFirst({ orderBy: { sortOrder: 'asc' } });
  if (fallback) return fallback.id;
  return (
    await prisma.scaleCategory.create({
      data: {
        name: categoryName,
        description: `自动创建（seed-scales）`,
        sortOrder: 99,
      },
    })
  ).id;
}

/**
 * 同步量表与题目（short_name 唯一键；无 short_name 的条目按 name 匹配）
 */
export async function seedScales() {
  let created = 0;
  let updated = 0;
  let skipped = 0;

  for (const row of SEED_DATA) {
    const { categoryName, scale: scaleData, questions } = row;
    const key = scaleData.shortName?.trim();
    if (!key) {
      const byName = await prisma.scale.findFirst({ where: { name: scaleData.name } });
      if (!byName) {
        const catId = await resolveCategoryId(categoryName);
        const createdScale = await prisma.scale.create({
          data: { ...scaleData, categoryId: catId },
        });
        if (questions.length) {
          await prisma.scaleQuestion.createMany({
            data: questions.map((q) => ({ ...q, scaleId: createdScale.id })),
          });
        }
        created += 1;
      } else {
        const catId = await resolveCategoryId(categoryName);
        await prisma.scale.update({
          where: { id: byName.id },
          data: { ...scaleData, categoryId: catId },
        });
        await prisma.scaleQuestion.deleteMany({ where: { scaleId: byName.id } });
        if (questions.length) {
          await prisma.scaleQuestion.createMany({
            data: questions.map((q) => ({ ...q, scaleId: byName.id })),
          });
        }
        updated += 1;
      }
      continue;
    }

    const catId = await resolveCategoryId(categoryName);
    const existing = await prisma.scale.findFirst({ where: { shortName: key } });

    if (existing) {
      await prisma.scale.update({
        where: { id: existing.id },
        data: { ...scaleData, categoryId: catId },
      });
      await prisma.scaleQuestion.deleteMany({ where: { scaleId: existing.id } });
      if (questions.length) {
        await prisma.scaleQuestion.createMany({
          data: questions.map((q) => ({ ...q, scaleId: existing.id })),
        });
      }
      updated += 1;
    } else {
      const s = await prisma.scale.create({
        data: { ...scaleData, categoryId: catId },
      });
      if (questions.length) {
        await prisma.scaleQuestion.createMany({
          data: questions.map((q) => ({ ...q, scaleId: s.id })),
        });
      }
      created += 1;
    }
  }

  console.log(`量表种子完成: 新建 ${created} / 更新 ${updated} / 跳过 ${skipped}`);
}

// 直接执行：node prisma/seed-scales.js
const runDirect =
  typeof process.argv[1] === 'string' && process.argv[1].includes('seed-scales.js');
if (runDirect) {
  seedScales()
    .catch((e) => {
      console.error(e);
      process.exit(1);
    })
    .finally(async () => {
      await prisma.$disconnect();
    });
}
